#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[10005];
        scanf("%s", S);
        int n = strlen(S);
        int seen[676] = {0};
        int distinct = 0;
        for (int i = 0; i < n - 1; ++i) {
            int idx = (S[i] - 'A') * 26 + (S[i + 1] - 'A');
            if (!seen[idx]) {
                seen[idx] = 1;
                ++distinct;
            }
        }
        printf("%d\n", distinct);
    }
    return 0;
}

