import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        s = data[i].strip()
        seen = [False] * 676
        cnt = 0
        for j in range(len(s) - 1):
            idx = (ord(s[j]) - 65) * 26 + (ord(s[j + 1]) - 65)
            if not seen[idx]:
                seen[idx] = True
                cnt += 1
        out.append(str(cnt))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

